// Fonction factorielle iterative (evite les overflow en utilisant long).
static long Factorial(int n) {
    long f = 1;
    for (int i = 2; i <= n; i++) f *= i;
    return f;
}

Console.WriteLine($"{"Puzzle",-12} {"n! (total)",25} {"n!/2 (accessibles)",25}");
