// Exemple guide : maximiser profit = 50x + 80y - x^2 - 2y^2 - xy.
// On minimise l'oppose (convention metaheuristique).
static double ProfitNeg(double[] sol)
{
    double x = sol[0], y = sol[1];
    double profit = 50*x + 80*y - x*x - 2*y*y - x*y;
    return -profit;
}

