// Fonctions de benchmark.

static double Sphere(double[] x) {
    double s = 0;
    for (int i = 0; i < x.Length; i++) s += x[i] * x[i];
    return s;
}

static double Rosenbrock(double[] x) {
    int n = x.Length;
    double s = 0;
    for (int i = 0; i < n - 1; i++) {
        double a = x[i + 1] - x[i] * x[i];
        double b = 1.0 - x[i];
        s += 100.0 * a * a + b * b;
    }
    return s;
}

